var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"이지수 씨의 말대로라면 이 좌표 어딘가에 있을 겁니다.","JPN":"ムラサメさんの言葉通りだとすると、この座標のどこかにいるはずです。","ENG":"According to Lee Jisoo, it should be somewhere around these coordinates.","TWN":"如果依照李智秀說的，那孩子應該就在這個座標某處。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"정말로 그 아이가... 이런 이면세계 어딘가에 있다고?","JPN":"本当にあの子が……こんな裏世界のどこかにいるの？","ENG":"That child is really somewhere in the Counterside...?","TWN":"真的嗎？那孩子……真的在這個異界某處？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"근거는 충분해.","JPN":"根拠は十分だ。","ENG":"The evidence is sufficient.","TWN":"證據很充分。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"당신이 가진 그 아이와의 인연을 따라온 거니까.","JPN":"お前の持つ、子との絆を辿ってきたんだからな。","ENG":"We followed the bond you share with that child.","TWN":"因為我們跟隨你和那孩子的緣分來到這裡。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"나와 그 아이의... 인연?","JPN":"私とあの子の……絆？","ENG":"A bond... between me and that child?","TWN":"我和那孩子的……緣分？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"아니, 그런 게 진짜로 당신 눈에 보인다고 해도 말이지...","JPN":"本当にそんなものがあなたに見えるとして……","ENG":"No, even if you really can see something like that...","TWN":"即便你真的能看到……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"당장 세상이 멸망하게 생겼는데, 한가롭게 날 돕고 있어도 괜찮은 거야?","JPN":"すぐにでも世界が滅亡するって時に、のんびり私を手伝っていてもいいのか？","ENG":"The world's on the verge of ending, and you're helping me like this?","TWN":"現在世界即將毀滅，這麼悠哉幫我也沒問題嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"타기리온이란 마왕이 어디 숨어있는지 찾아야 한다면서?","JPN":"タギリオンという魔王がどこに隠れてるのか、探さなくちゃならないんだろう？","ENG":"Didn't you say you had to find the Demon Lord Thagirion?","TWN":"你不是說要找到魔王塔基里翁藏在哪嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"약속드렸잖아요.","JPN":"約束しましたからね。","ENG":"We made a promise, didn't we?","TWN":"我答應過你啦。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"저희가 서생 씨를 찾는 걸 도와주면, 저희도 부인을 돕겠다고 했으니까요.","JPN":"ショウさんを探すのを手伝ってくれれば、僕たちも夫人を手伝うと。","ENG":"We told you that if you helped us find Seosaeng, we'd help you in return.","TWN":"如果幫我們找到書生，我們也會幫你。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그리고 부인의 아이를 찾도록 돕는 건, 타기리온을 찾는다는 저희 목적과도 일치하는 면이 있거든요.","JPN":"それに夫人のお子さんを探すのを手伝うのは、タギリオンを探すという僕たちの目的とも重なる部分があるんです。","ENG":"And helping you find your child also works toward our goal of locating Thagirion.","TWN":"而且幫你找到孩子，和我們尋找塔基里翁的目標也有些重疊。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"마왕을 찾는 게... 그 아이랑 무슨 연관이 있다는 거지?","JPN":"魔王を探すのが……あの子と何の関係がある？","ENG":"Finding the Demon Lord... what does that have to do with that child?","TWN":"尋找魔王……和孩子有什麼關聯？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"정확히는 북방합의체의 연구와 연관이 있지.","JPN":"正確には北方合意体の研究と関係がある。","ENG":"More precisely, it's connected to research conducted by the Northern Union.","TWN":"確切來說，是與北方和議會的研究有關。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"북방합의체?","JPN":"北方合意体？","ENG":"The Northern Union?","TWN":"北方和議會？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그들은 과거, 이면세계 한복판에서 살아있는 거대한 유기체를 발견하고 연구했어.","JPN":"彼らは過去、裏世界の真ん中で生きている巨大な有機体を発見し研究した。","ENG":"In the past, they discovered a massive living organism in the middle of the Counterside and began studying it.","TWN":"他們曾在異界中心發現一個活著的巨大有機體，並對此進行研究。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그리고 연구 끝에, 그것이 행성 하나를 감쌀 만큼 거대한 나무의 일부라는 걸 밝혀냈지.","JPN":"そして研究の末、それが惑星を丸ごと包み込めるほど巨大な木の一部だということを突き止めたんだ。","ENG":"After years of research, they determined it was part of a colossal tree large enough to envelop an entire planet.","TWN":"研究後發現，那是包覆整個行星的巨樹的一部分。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"나무라면 설마...","JPN":"木って、まさか……","ENG":"A tree... You don't mean–","TWN":"那棵樹該不會……？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"도시의 대균열에 나타난 그것과 연관이 있는 건가?","JPN":"都市の大亀裂に現れたあれと関係があるのか？","ENG":"Is it connected to the one that appeared in the Grand Dimension Crevice above the city?","TWN":"和城市大峽谷中出現的那個有關嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그래.","JPN":"そうだ。","ENG":"Yes.","TWN":"是啊。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"과학자들이 청동나무라 부르는 이 나무가 발견된 이면세계도, 한때는 사람이 살던 평범한 세상이었다네.","JPN":"科学者たちが青銅の木と呼んでいるこの木が発見された裏世界も、かつては人の住む平凡な世界だった。","ENG":"The part of the Counterside where scientists discovered this tree they call the Bronze Tree was once an ordinary world where people lived.","TWN":"被科學家稱為青銅樹的那棵樹發現的異界，也是曾有人居住的普通世界。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"하지만 거대한 뿌리가 나타나, 세상의 모든 가능성을 빨아들이면서 지금의 황폐한 모습이 되고 말았지.","JPN":"だが巨大な根が現れ、世界のすべての可能性を吸い取られて、今のように荒れてしまったんだ。","ENG":"But a massive root appeared and absorbed every possibility within the world, leaving it in the desolate state you see now.","TWN":"但巨大的根出現後吸收了世界的所有可能性，變成了現在荒蕪的模樣。"},"stage":{"bg":"OMEN_CHARADE_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"터무니 없는 얘기지 않나?","JPN":"とんでもない話だと思うだろう？","ENG":"Hard to believe, isn't it?","TWN":"這故事也太誇張了吧？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"누구도 쉽게 납득하지 못할 걸세. 그런 걸 직접 겪어보기 전까진 말이야.","JPN":"簡単に納得できる人なんていないさ。身をもって経験するまではね。","ENG":"No one would accept such a story easily. Not unless they experienced it themselves.","TWN":"除非親眼見到，否則沒有人會輕易相信。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그 나무를 조종하는 게 마왕 타기리온이란 작자인가?","JPN":"その木を操っているのが魔王タギリオンという奴なのか？","ENG":"So the one controlling that tree is the Demon Lord Thagirion?","TWN":"操控那棵樹的就是魔王塔基里翁嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그렇기 때문에 우리가 타기리온을 찾으려면 그 나무의 원류를 찾아 거슬러가야 한다네.","JPN":"だから我々がタギリオンを探し出すには、その木の源を見つけて、遡らなければならないのさ。","ENG":"That's why, if we want to find Thagirion, we must trace the origin of that tree.","TWN":"所以如果我們要找到塔基里翁，就得追溯到樹的源頭。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그리고 자네 아이가 그 나무의 정수를 품고 있지.","JPN":"そして君の子どもがその木の精髄を持っている。","ENG":"And your child carries the essence of that tree.","TWN":"而你的孩子擁有那樹的精華。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"청동나무의... 심장.","JPN":"青銅の木の……心臓。","ENG":"The Bronze Tree's... heart.","TWN":"青銅樹的……心臟。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그게 우리가 그 흔적을 쫓는 이유다.","JPN":"私たちがその痕跡を追っている理由だ。","ENG":"That's why we're following its traces.","TWN":"這就是我們追蹤痕跡的原因。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"모든 것은 본질로 되돌아가기 마련이니까.","JPN":"すべては本質に戻るものだからな。","ENG":"Everything eventually returns to its origin.","TWN":"萬物終將回歸本質。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"뭔가 보이기 시작했군.","JPN":"何かが見えてきた。","ENG":"Something's starting to appear.","TWN":"我開始有點看懂了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"오...","JPN":"おお……","ENG":"Oh...","TWN":"哦……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};